import { useState, useRef, useCallback } from "react";
import { Loader2, X } from "lucide-react";
import { useJournalEntriesQuery, useJournalDatesQuery, useGenerateJournalMutation } from "../../hooks/use-tauri-query";
import { JournalFeed } from "./JournalFeed";
import { DateJumper } from "./DateJumper";
import { GenerateDialog } from "./GenerateDialog";

export function DashboardView() {
  const [showGenerateDialog, setShowGenerateDialog] = useState(false);
  const [showErrorBanner, setShowErrorBanner] = useState(true);
  const feedRef = useRef<HTMLDivElement>(null);

  const { data: entries = [] } = useJournalEntriesQuery();
  const { data: dates = [] } = useJournalDatesQuery();
  const generateMutation = useGenerateJournalMutation();

  const today = new Date().toISOString().slice(0, 10);

  const handleDateClick = useCallback((date: string) => {
    const el = document.getElementById(`journal-${date}`);
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  }, []);

  const handleGenerate = useCallback(
    (date: string, extraItems?: string[]) => {
      setShowErrorBanner(true);
      generateMutation.mutate({ date, extraItems });
    },
    [generateMutation]
  );

  return (
    <div className="flex flex-1 flex-col overflow-hidden">
      {/* Dashboard toolbar */}
      <div className="flex items-center justify-between border-b border-border bg-bg px-5 py-3">
        <div className="flex items-center gap-3">
          <h1 className="text-sm font-semibold text-fg">Work Journal</h1>
        </div>
        <button
          onClick={() => setShowGenerateDialog(true)}
          disabled={generateMutation.isPending}
          className="rounded-md bg-accent px-3 py-1.5 text-xs font-semibold text-white hover:bg-accent/90 disabled:opacity-50"
        >
          ✨ Generate Today's Summary
        </button>
      </div>

      {/* Generation status banner */}
      {generateMutation.isPending && (
        <div className="flex items-center gap-2 border-b border-border bg-accent/5 px-5 py-2.5">
          <Loader2 size={14} className="animate-spin text-accent" />
          <span className="text-xs text-fg-subtle">
            Generating summary… this may take a minute or two
          </span>
        </div>
      )}

      {generateMutation.isError && showErrorBanner && (
        <div className="flex items-center justify-between border-b border-red-500/20 bg-red-500/5 px-5 py-2.5">
          <span className="text-xs text-red-500">
            Generation failed: {generateMutation.error.message}
          </span>
          <button
            onClick={() => setShowErrorBanner(false)}
            className="text-red-500 hover:text-red-400"
          >
            <X size={14} />
          </button>
        </div>
      )}

      {/* Feed + Date Jumper */}
      <div className="flex flex-1 overflow-hidden">
        <div ref={feedRef} className="flex-1 overflow-y-auto px-8 py-6">
          <div className="mx-auto max-w-[720px]">
            <JournalFeed entries={entries} />
          </div>
        </div>

        <DateJumper dates={dates} onDateClick={handleDateClick} />
      </div>

      {/* Generate dialog */}
      {showGenerateDialog && (
        <GenerateDialog
          date={today}
          onClose={() => setShowGenerateDialog(false)}
          onGenerate={handleGenerate}
        />
      )}
    </div>
  );
}

