export function useGenerateJournalMutation() {
  const queryClient = useQueryClient();
  return useMutation<JournalEntry, Error, { date: string; extraItems?: string[] }>({
    mutationFn: ({ date, extraItems }) =>
      invoke("generate_journal_entry", { date, extraItems }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["journal-entries"] });
      queryClient.invalidateQueries({ queryKey: ["journal-dates"] });
    },
  });
}

