      .split("\n")
      .map((line) => line.replace(/^[-*]\s*/, "").trim())
      .filter((line) => line.length > 0);

    onGenerate(date, items.length > 0 ? items : undefined);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
      <div className="w-[520px] rounded-lg border border-border bg-bg-raised shadow-xl">
        <div className="flex items-center justify-between border-b border-border px-6 py-4">
          <h2 className="text-sm font-semibold text-fg">Generate Daily Summary</h2>
          <button
            onClick={onClose}
            className="text-fg-subtle hover:text-fg"
          >
            <X size={16} />
          </button>
        </div>

        <div className="p-6">
          <div className="mb-1 text-sm font-semibold text-fg">
            Generate summary for {formattedDate}
          </div>

          <div className="mb-5 mt-4">
            <label className="mb-1.5 block text-[11px] font-semibold uppercase text-fg-muted">
              Anything else to include?
            </label>
            <div className="mb-2 text-[11px] text-fg-subtle">
              Add non-code work — meetings, reviews, planning, design sessions, etc.
            </div>
            <textarea
              value={extraItems}
              onChange={(e) => setExtraItems(e.target.value)}
              className="w-full rounded-md border border-border bg-bg p-2.5 text-xs leading-relaxed text-fg placeholder:text-fg-subtle focus:border-accent focus:outline-none"
              rows={4}
              placeholder={"e.g.\n- Led sprint planning, scoped Q2 milestones\n- Reviewed 2 architecture RFCs\n- Paired with Sarah on auth migration design"}
            />
          </div>

          <div className="flex justify-end gap-2">
            <button
              onClick={onClose}
              className="rounded-md border border-border bg-bg px-4 py-2 text-xs text-fg hover:bg-bg-hover"
            >
              Cancel
            </button>
            <button
              onClick={handleGenerate}
              className="rounded-md bg-accent px-4 py-2 text-xs font-semibold text-white hover:bg-accent/90"
            >
              ✨ Generate
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

